+        //
+        // Check if we have read at least one byte
+        //
+        if (numBytesRead > 0)
+        {
+            errorCode = SBG_NO_ERROR;
+        }
+        else
+        {
+            errorCode = SBG_READ_ERROR;
+            numBytesRead = 0;
+        }
+        
+        //
+        // If we can, returns the number of read bytes
+        //
+        if (pReadBytes)
+        {
+            *pReadBytes = (size_t)numBytesRead;
+        }
+	}
+	else
+	{
+		errorCode = SBG_NULL_POINTER;
+	}
+	
+	return errorCode;
+}

