+	char comPortPath[32];
+	COMMTIMEOUTS comTimeOut;
+	DCB comState;
+	uint32 deviceNum;
+	HANDLE hSerialDevice;
+
+	assert(pHandle);
+
+	//
+	// Extract device number
+	//
+	if (sscanf_s(deviceName, "COM%i", &deviceNum) == 1)
+	{
+		//
+		// Build the com port path
+		//
+		sprintf_s(comPortPath, 32, "\\\\.\\COM%i", deviceNum);
