+		//
+		// Serial port successfully purged
+		//
+		return SBG_NO_ERROR;
+	}
+	else
+	{
+		//
+		// Flush has failed
+		//
+		sbgGetWindowsErrorMsg(errorMsg);
+		errorCode = SBG_ERROR;
+		SBG_LOG_ERROR(SBG_ERROR, "PurgeComm failed: %s", errorMsg);			
+	}
