+	// Test that we don't have any error
+	//
+	if (retValue != SOCKET_ERROR)
+	{
+		//
+		// Returns the number of read bytes
+		//
+		*pReadBytes = (size_t)retValue;
+	}
+	else
+	{
+		#ifdef WIN32
+		//
+		// Get the last error during the read
+		//
+		retValue = WSAGetLastError();
