+		if (retValue== WSAEWOULDBLOCK)
+		{
+			errorCode = SBG_NOT_READY;
+		}
+		else
+		{
+			errorCode = SBG_ERROR;
+		}
+		#else
+		errorCode = SBG_NOT_READY;
+		#endif
+	}
+
+	return errorCode;
+}

