+				break;
+			case SBG_VERSION_QUALIFIER_BETA:
+				strcat(pBuffer, "beta");
+				break;
+			case SBG_VERSION_QUALIFIER_RC:
+				strcat(pBuffer, "rc");
+				break;
+			case SBG_VERSION_QUALIFIER_STABLE:
