+	
+	assert(pHandle);
+	
+	//
+	// Init stream buffer for output and Build payload
+	//
+	sbgStreamBufferInitForWrite(&outputStream, outputBuffer, sizeof(outputBuffer));
+	sbgStreamBufferWriteUint32LE(&outputStream, modelId);
